# --- Sanitization Helpers ---

# Allowlisted endpoints to prevent cardinality explosion
KNOWN_ENDPOINTS = frozenset({
    "/",
    "/api/data",
    "/api/order",
    "/api/user/login",
    "/api/user/logout",
    "/health",
    "/ready",
    "/metrics",
})

MAX_LABEL_LENGTH = 128


def sanitize_endpoint(endpoint: str) -> str:
    """Sanitize endpoint label to prevent cardinality explosion and injection."""
    if endpoint in KNOWN_ENDPOINTS:
        return endpoint
    # Normalize unknown endpoints to prevent high cardinality
    # Strip path parameters and collapse to base path
    parts = endpoint.strip("/").split("/")
    if len(parts) >= 2:
        base = "/" + "/".join(parts[:2])
        if base in KNOWN_ENDPOINTS or any(base.startswith(k.rstrip("/")) for k in KNOWN_ENDPOINTS):
            return base
    return "/unknown"


def sanitize_label(value: str) -> str:
    """Sanitize a generic label value."""
    if not isinstance(value, str):
        value = str(value)
    # Remove newlines and carriage returns to prevent log/metric injection
    value = value.replace("\n", "").replace("\r", "")
    return value[:MAX_LABEL_LENGTH]


# --- Metrics Authentication ---

METRICS_TOKEN = os.environ.get("METRICS_AUTH_TOKEN", None)


def require_metrics_auth():
    """Verify authentication for metrics endpoint."""
    if METRICS_TOKEN is None:
        # If no token configured, only allow from localhost in production
        if os.environ.get("FLASK_ENV") == "production":
            remote_addr = request.remote_addr
            if remote_addr not in ("127.0.0.1", "::1"):
                abort(403)
        return

    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        abort(401)

    provided_token = auth_header[7:]
    if not secrets.compare_digest(provided_token, METRICS_TOKEN):
        abort(403)


# --- Flask Application ---

def create_app():
    app = Flask(__name__)

    # Security configurations
    app.config["MAX_CONTENT_LENGTH"] = 1 * 1024 * 1024  # 1MB max request size
    app.config["SECRET_KEY"] = os.environ.get("SECRET_KEY", secrets.token_hex(32))

    # Trust proxy headers only if behind a reverse proxy
    if os.environ.get("BEHIND_PROXY", "false").lower() == "true":
        app.wsgi_app = ProxyFix(app.wsgi_app, x_for=1, x_proto=1, x_host=1, x_prefix=1)

    # Set application info
    APP_INFO.info({
        "version": os.environ.get("APP_VERSION", "1.0.0"),
        "environment": os.environ.get("FLASK_ENV", "development"),
        "name": "flask-prometheus-app",
    })

    # --- Security Headers Middleware ---
    @app.after_request
    def set_security_headers(response):
        response.headers["X-Content-Type-Options"] = "nosniff"
        response.headers["X-Frame-Options"] = "DENY"
        response.headers["X-XSS-Protection"] = "1; mode=block"
        response.headers["Strict-Transport-Security"] = "max-age=31536000; includeSubDomains"
        response.headers["Cache-Control"] = "no-store"
        response.headers["Content-Security-Policy"] = "default-src 'none'"
        # Remove server header
        response.headers.pop("Server", None)
        return response

    # --- Request Instrumentation Middleware ---
    @app.before_request
    def before_request_metrics():
        g.start_time = time.monotonic()
        endpoint = sanitize_endpoint(request.path)
        method = sanitize_label(request.method)
        REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).inc()

    @app.after_request
    def after_request_metrics(response):
        if hasattr(g, "start_time"):
            latency = time.monotonic() - g.start_time
            endpoint = sanitize_endpoint(request.path)
            method = sanitize_label(request.method)
            status = str(response.status_code)

            REQUEST_COUNT.labels(
                method=method,
                endpoint=endpoint,
                http_status=status,
            ).inc()

            REQUEST_LATENCY.labels(
                method=method,
                endpoint=endpoint,
            ).observe(latency)

            response_size = response.content_length or 0
            RESPONSE_SIZE.labels(
                method=method,
                endpoint=endpoint,
            ).observe(response_size)

            REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

        return response

    @app.errorhandler(Exception)
    def handle_exception(e):
        endpoint = sanitize_endpoint(request.path)
        error_type = sanitize_label(type(e).__name__)
        ERROR_COUNT.labels(error_type=error_type, endpoint=endpoint).inc()

        # Don't leak internal error details
        if hasattr(e, "code") and isinstance(e.code, int):
            return jsonify({"error": "Request failed"}), e.code
        return jsonify({"error": "Internal server error"}), 500

    # --- Metrics Endpoint ---
    @app.route("/metrics")
    def metrics():
        require_metrics_auth()

        # Support multiprocess mode (e.g., gunicorn with multiple workers)
        if "prometheus_multiproc_dir" in os.environ:
            registry = CollectorRegistry()
            multiprocess.MultiProcessCollector(registry)
            metrics_output = generate_latest(registry)
        else:
            metrics_output = generate_latest(REGISTRY)

        return Response(
            metrics_output,
            mimetype=CONTENT_TYPE_LATEST,
        )

